const rows = items;

// Ambil tanggal kemarin
const kemarin = new Date();
kemarin.setDate(kemarin.getDate() - 1);
const tanggalKemarin = kemarin.toISOString().split('T')[0]; // format: 2026-06-12

// Filter hanya order kemarin
const orderKemarin = rows.filter(row => {
  const timestamp = row.json['Timestamp'] || '';
  return timestamp.startsWith(tanggalKemarin);
});

// Kalau tidak ada order kemarin
if (orderKemarin.length === 0) {
  const laporan = `📊 *LAPORAN HARIAN*
📅 ${kemarin.toLocaleDateString('id-ID', { 
  weekday: 'long', year: 'numeric',
  month: 'long', day: 'numeric' })}

Tidak ada order masuk kemarin. 😴

Semangat jualan hari ini! 💪`;
  return [{ json: { laporan, totalOrder: 0, totalItem: 0, totalPendapatan: 0, } }];
}

// Hitung total
let totalItem = 0;
let totalPendapatan = 0;
const detailPesanan = [];


for (const row of orderKemarin) {
  const pesanan = row.json['Pesanan'] || '';
  const nama = row.json['Nama'] || '';
  const totalHarga = parseInt(row.json['Total Harga']) || 0;

  const angka = pesanan.match(/\d+$/);
  const jumlah = parseInt(row.json['Jumlah Item']) || 1;
  totalItem += jumlah;
  totalPendapatan += totalHarga;

  const hargaFormatted = 'Rp ' + totalHarga.toLocaleString('id-ID');
  detailPesanan.push(`• ${nama}: ${pesanan} => ${hargaFormatted}`);
}

const laporan = `📊 *LAPORAN HARIAN*
📅 ${kemarin.toLocaleDateString('id-ID', { 
  weekday: 'long', year: 'numeric',
  month: 'long', day: 'numeric' })}

📦 Total Order: ${orderKemarin.length} pesanan
🛒 Total Item: ${totalItem} item
💰 Total Pendapatan: ${totalPendapatan}


📋 *Detail Pesanan:*
${detailPesanan.join('\n')}

Semangat jualan hari ini! 💪`;

return [{ json: { laporan, totalOrder: orderKemarin.length, totalItem, totalPendapatan } }];
